"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useSession } from "next-auth/react";
import {
  LayoutDashboard, Users, BarChart2, X,
  ShieldCheck, ChevronLeft, ChevronRight,
  ShieldAlert, Heart, CalendarClock, Settings, FileText, ClipboardList,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { getInitials } from "@/lib/utils";

type NavItem  = { href: string; label: string; icon: React.ElementType };
type NavGroup = { label: string; items: NavItem[] };

/* Spec §4.1 — 8 nav items */
const navGroups: NavGroup[] = [
  {
    label: "Overview",
    items: [
      { href: "/hr/dashboard", label: "Dashboard", icon: LayoutDashboard },
      { href: "/hr/employees", label: "Employees", icon: Users },
    ],
  },
  {
    label: "Compliance & Wellness",
    items: [
      { href: "/hr/compliance", label: "PE Compliance",   icon: ShieldAlert },
      { href: "/hr/wellness",   label: "Wellness Trends", icon: Heart },
    ],
  },
  {
    label: "Reports & Tools",
    items: [
      { href: "/hr/reports",    label: "Reports & Exports",  icon: BarChart2 },
      { href: "/hr/scheduling", label: "Bulk Scheduling",    icon: CalendarClock },
      { href: "/hr/audit",      label: "Audit Trail",        icon: ClipboardList },
    ],
  },
  {
    label: "System",
    items: [
      { href: "/hr/settings", label: "Account Settings", icon: Settings },
    ],
  },
];

interface HrSidebarProps {
  isOpen?: boolean;
  onClose?: () => void;
  collapsed?: boolean;
  onToggleCollapse?: () => void;
}

export function HrSidebar({ isOpen = true, onClose, collapsed = false, onToggleCollapse }: HrSidebarProps) {
  const pathname = usePathname();
  const { data: session } = useSession();

  const firstName = session?.user?.firstName ?? "";
  const lastName  = session?.user?.lastName  ?? "";
  const initials  = firstName && lastName ? getInitials(firstName, lastName) : "HR";

  const allItems = navGroups.flatMap((g) => g.items);

  return (
    <>
      {isOpen && onClose && (
        <div className="fixed inset-0 z-40 bg-black/60 backdrop-blur-sm lg:hidden" onClick={onClose} />
      )}

      <aside
        className={cn(
          "fixed inset-y-0 left-0 z-50 flex flex-col",
          "transition-all duration-300 ease-in-out",
          "lg:static lg:translate-x-0",
          collapsed ? "lg:w-17" : "lg:w-64",
          isOpen ? "translate-x-0 w-64" : "-translate-x-full w-64"
        )}
        style={{
          backgroundColor: "#08036A",
          borderRight: "3px solid #E00500",
        }}
      >
        {/* Logo */}
        <div className={cn(
          "flex h-16 items-center shrink-0",
          collapsed ? "justify-center px-0" : "justify-between px-4"
        )}
          style={{ borderBottom: "1px solid rgba(255,255,255,0.1)" }}
        >
          {!collapsed && (
            <Link href="/hr/dashboard" className="flex items-center gap-2.5 min-w-0">
              <div style={{
                width: 32, height: 32, borderRadius: 10, flexShrink: 0,
                background: "#E00500", border: "1px solid rgba(255,255,255,0.2)",
                display: "flex", alignItems: "center", justifyContent: "center",
              }}>
                <ShieldCheck style={{ width: 16, height: 16, color: "white" }} />
              </div>
              <div className="min-w-0">
                <p style={{ fontWeight: 800, color: "white", fontSize: 13, lineHeight: 1, letterSpacing: "0.04em" }}>NWD HR</p>
                <p style={{ fontSize: 9, color: "rgba(255,255,255,0.45)", marginTop: 2, letterSpacing: "0.14em", textTransform: "uppercase" }}>Staff Portal</p>
              </div>
            </Link>
          )}
          {collapsed && (
            <Link href="/hr/dashboard" style={{
              display: "flex", width: 32, height: 32, alignItems: "center", justifyContent: "center",
              borderRadius: 10, background: "#E00500", border: "1px solid rgba(255,255,255,0.2)",
            }}>
              <ShieldCheck style={{ width: 14, height: 14, color: "white" }} />
            </Link>
          )}
          {onClose && (
            <Button variant="ghost" size="icon" className="lg:hidden shrink-0" style={{ color: "rgba(255,255,255,0.7)" }} onClick={onClose}>
              <X className="h-4 w-4" />
            </Button>
          )}
          {onToggleCollapse && (
            <Button
              variant="ghost" size="icon"
              className={cn("hidden lg:flex shrink-0 h-7 w-7 rounded-lg", collapsed && "mx-auto")}
              style={{ color: "rgba(255,255,255,0.6)" }}
              onClick={onToggleCollapse}
            >
              {collapsed ? <ChevronRight className="h-3.5 w-3.5" /> : <ChevronLeft className="h-3.5 w-3.5" />}
            </Button>
          )}
        </div>

        {/* Navigation */}
        <nav className="flex-1 overflow-y-auto scrollbar-thin px-2 py-3">
          {collapsed ? (
            <div className="space-y-0.5">
              {allItems.map((item) => {
                const isActive = pathname === item.href || (item.href !== "/hr/dashboard" && pathname.startsWith(item.href));
                const Icon = item.icon;
                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    onClick={onClose}
                    title={item.label}
                    style={{
                      display: "flex", justifyContent: "center", alignItems: "center",
                      height: 40, width: 40, margin: "0 auto", borderRadius: 10,
                      transition: "all 0.15s", position: "relative",
                      background: isActive ? "rgba(255,255,255,0.18)" : "transparent",
                      border: isActive ? "1px solid rgba(255,255,255,0.25)" : "1px solid transparent",
                    }}
                    className="group"
                  >
                    <Icon style={{ width: 16, height: 16, color: isActive ? "white" : "rgba(255,255,255,0.5)" }} />
                    <span className="pointer-events-none absolute left-full ml-3 whitespace-nowrap rounded-lg bg-white border border-gray-200 px-2.5 py-1.5 text-xs font-medium text-gray-800 shadow-md opacity-0 group-hover:opacity-100 transition-opacity z-50">
                      {item.label}
                    </span>
                  </Link>
                );
              })}
            </div>
          ) : (
            <div className="space-y-4">
              {navGroups.map((group) => (
                <div key={group.label}>
                  <p style={{ padding: "0 12px", marginBottom: 4, fontSize: 9, fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.18em", color: "rgba(255,255,255,0.3)" }}>
                    {group.label}
                  </p>
                  <div className="space-y-0.5">
                    {group.items.map((item) => {
                      const isActive = pathname === item.href || (item.href !== "/hr/dashboard" && pathname.startsWith(item.href));
                      const Icon = item.icon;
                      return (
                        <Link
                          key={item.href}
                          href={item.href}
                          onClick={onClose}
                          style={{
                            display: "flex", alignItems: "center", gap: 10,
                            padding: "9px 12px", borderRadius: 10, fontSize: 13, fontWeight: 500,
                            transition: "all 0.15s", border: "1px solid transparent", textDecoration: "none",
                            background: isActive ? "rgba(255,255,255,0.16)" : "transparent",
                            borderColor: isActive ? "rgba(255,255,255,0.2)" : "transparent",
                            color: isActive ? "white" : "rgba(255,255,255,0.55)",
                          }}
                        >
                          <Icon style={{ width: 16, height: 16, flexShrink: 0, color: isActive ? "white" : "rgba(255,255,255,0.45)" }} />
                          <span style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{item.label}</span>
                          {isActive && (
                            <div style={{ width: 4, height: 4, borderRadius: "50%", background: "#E00500", flexShrink: 0 }} />
                          )}
                        </Link>
                      );
                    })}
                  </div>
                </div>
              ))}
            </div>
          )}
        </nav>

        {/* Tagline */}
        {!collapsed && (
          <div style={{ padding: "8px 16px", borderTop: "1px solid rgba(255,255,255,0.07)", borderBottom: "1px solid rgba(255,255,255,0.07)" }}>
            <p style={{ fontSize: 9, color: "rgba(255,255,255,0.25)", fontStyle: "italic", letterSpacing: "0.04em", textAlign: "center" }}>
              "Your Health is Our Commitment"
            </p>
          </div>
        )}

        {/* User footer */}
        <div style={{ padding: collapsed ? "12px 8px" : "12px 16px", borderTop: "1px solid rgba(255,255,255,0.1)" }}>
          {collapsed ? (
            <div style={{ display: "flex", width: 36, height: 36, margin: "0 auto", alignItems: "center", justifyContent: "center", borderRadius: 10, background: "rgba(255,255,255,0.12)", border: "1px solid rgba(255,255,255,0.18)" }}>
              <span style={{ fontSize: 11, fontWeight: 700, color: "white" }}>{initials}</span>
            </div>
          ) : (
            <div style={{ display: "flex", alignItems: "center", gap: 10, borderRadius: 10, padding: 8 }}>
              <div style={{ width: 32, height: 32, flexShrink: 0, display: "flex", alignItems: "center", justifyContent: "center", borderRadius: "50%", background: "#E00500", border: "2px solid rgba(255,255,255,0.25)", fontSize: 11, fontWeight: 700, color: "white" }}>
                {initials}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <p style={{ fontSize: 12, fontWeight: 600, color: "white", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", lineHeight: 1 }}>{firstName} {lastName}</p>
                <p style={{ fontSize: 10, color: "rgba(255,255,255,0.38)", marginTop: 2 }}>HR Staff</p>
              </div>
              <div style={{ display: "flex", height: 18, alignItems: "center", borderRadius: 6, background: "#E00500", padding: "0 6px" }}>
                <span style={{ fontSize: 9, fontWeight: 700, color: "white", letterSpacing: "0.06em" }}>HR</span>
              </div>
            </div>
          )}
        </div>
      </aside>
    </>
  );
}
